    public function getTaskByTicketId($ticketId) {
        $query = $this->db->placehold("
            SELECT 
                * 
            FROM 
                __users,
                __orders,
                __user_balance,
                __pr_tasks
            WHERE 
                __pr_tasks.ticketId = ?
            AND
                __users.id = __pr_tasks.user_id
            AND 
                __user_balance.zaim_number = __pr_tasks.number
            AND 
                __orders.id = __pr_tasks.user_balance_id
        ", (int) $ticketId);
        $query .= $this->getLimit($query);
        $this->db->query($query);
        $result = $this->db->results();
        return $result;
    }

