        $query = $this->db->placehold('DELETE FROM __pr_tasks
            WHERE task_date = "'.$data.'" AND manager_id IN ('.$arr .")");
        $this->db->query($query);
    }


    public function existingTask($number, $plus = false, $task_date = null){
        if ($task_date === null) {
            $task_date = date("Y-m-d");
        }

        $selectQuery = $this->db->placehold("Select id FROM __pr_tasks WHERE task_date = ? and number = ?", (string)$task_date, $number);
        $this->db->query($selectQuery);
        return $this->db->results();

    }


