    /**
     * @param $data
     * @return array|false
     */
    public function get_tasks($data)
    {
        $filter_manager = '';
        $filter_period = '';
        $filter_closed = '';
        $organization_join = '';
        $organization_filter = '';
        if (!empty($data['manager_id'])) {
            $filter_manager = $this->db->placehold("AND t.manager_id = ?", $data['manager_id']);
        }
        if (!empty($data['period'])) {
            $filter_period = $this->db->placehold("AND t.period = ?", $data['period']);
        }
        if (!empty($data['closed'])) {
            $filter_closed = $this->db->placehold("AND t.close = 0 AND t.prolongation = 0");
        }
        if (!empty($data['organization_id'])) {
            $organization_join = "
                LEFT JOIN s_contracts AS c ON c.number = t.number
                LEFT JOIN s_orders AS o ON o.id = c.order_id
            ";
            $organization_filter = $this->db->placehold(" AND o.organization_id = ?", (int)$data['organization_id']);
        }

        $query = $this->db->placehold("Select t.id,u.id as user_id,u.phone_mobile, t.timezone,u.lastname, u.firstname,u.patronymic,b.ostatok_od, b.ostatok_percents,b.ostatok_peni,b.prolongation_amount,b.zaim_date,b.payment_date,b.zayavka,b.zaim_number from __pr_tasks t
                                    JOIN __users u on t.user_id = u.id
                                    LEFT JOIN s_user_balance b on t.user_balance_id = b.id
                                    $organization_join
                                    WHERE 1  
                                    $filter_manager 
                                    $filter_period
                                    $filter_closed
                                    $organization_filter
                                    AND t.task_date BETWEEN ? AND ?
                                    ",
            $data['task_date_from'], $data['task_date_to']);

        $this->db->query($query);
        return $this->db->results();
    }

