    public function getCallsBlacklistUsers($userId) {
        if (is_array($userId)) {
            $user_query = $this->db->placehold("user_id IN (?@)", $userId);
        } else {            
            $user_query = $this->db->placehold("user_id = ?", (int)$userId);
        }
        $query = $this->db->placehold("
            SELECT *  FROM calls_blacklist
            WHERE $user_query and deleted_at is null
        ");
        $this->db->query($query);
        if (is_array($userId)) {
            return $this->db->results();
        } else {
            return $this->db->result();
        }
    }

