                                          WHERE created = ?
                                         ", $date);
        $this->db->query($query);
        return $this->db->result();
    }

    /**
     * Проверяет, были ли уже отправлены недозвоны на сегодня для конкретной организации
     * @param int $organizationId
     * @return object|null
     */
    public function existsMissedCallsForOrganization($organizationId) {
        $date = date("Y-m-d");
        
        // Проверяем, есть ли поле organization_id в таблице
        $checkColumn = $this->db->placehold("SHOW COLUMNS FROM missed_calls LIKE 'organization_id'");
        $this->db->query($checkColumn);
        $columnExists = $this->db->result();
        
        if ($columnExists) {
            // Используем проверку по organization_id
            $query = $this->db->placehold("SELECT * FROM missed_calls 
                                              WHERE created = ? AND organization_id = ?
                                             ", $date, (int)$organizationId);
        } else {
            // Fallback: проверяем только по дате (старая логика)
            // Это не идеально, но работает если поле еще не добавлено
            $query = $this->db->placehold("SELECT * FROM missed_calls 
                                              WHERE created = ?
                                             ", $date);
        }
        
        $this->db->query($query);
        return $this->db->result();
    }

